import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import products from "../data/ProductData"; // dummy data fallback
import "../index.css";

const Checkout = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [formData, setFormData] = useState({
    date: "",
    category: "",
    modeOfPayment: "",
    issue: "",
  });
  const [orderPlaced, setOrderPlaced] = useState(false);

  useEffect(() => {
    if (!id) return;

    // 1️⃣ Try dummy data first
    const dummy = products.find((p) => String(p.id) === id);
    if (dummy) {
      setProduct(dummy);
      return;
    }

    // 2️⃣ Fetch from backend (Shop.js products)
    axios
      .get(`http://localhost:5000/api/products/${id}`)
      .then((res) => {
        if (res.data) setProduct(res.data);
        else setProduct({ name: "Unknown Product", price: 0, _id: id });
      })
      .catch((err) => {
        console.error("Error loading product:", err);
        setProduct({ name: "Unknown Product", price: 0, _id: id });
      });
  }, [id]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setOrderPlaced(true);

    // You can later POST this order to backend
    console.log("Order placed:", { product, ...formData });

    setTimeout(() => navigate("/orders"), 2000);
  };

  if (!product) return <p>Loading product...</p>;
  if (orderPlaced) return <h2>✅ Order placed successfully!</h2>;

  return (
    <div className="checkout-container">
      <h2>Checkout</h2>
      <div className="checkout-details">
        <p><strong>Product:</strong> {product.name}</p>
        <p><strong>Price:</strong> ₹{product.price}</p>
      </div>

      <form onSubmit={handleSubmit} className="checkout-form">
        <label>Date of Purchase:</label>
        <input type="date" name="date" value={formData.date} onChange={handleChange} required />

        <label>Category:</label>
        <input type="text" name="category" value={formData.category} onChange={handleChange} required />

        <label>Mode of Payment:</label>
        <select name="modeOfPayment" value={formData.modeOfPayment} onChange={handleChange} required>
          <option value="">Select</option>
          <option value="UPI">UPI</option>
          <option value="Credit Card">Credit Card</option>
          <option value="Debit Card">Debit Card</option>
          <option value="Cash on Delivery">Cash on Delivery</option>
        </select>

        <label>Any Issue or Note:</label>
        <textarea name="issue" value={formData.issue} onChange={handleChange} />

        <button type="submit" className="place-order-btn">Place Order</button>
      </form>
    </div>
  );
};

export default Checkout;
